vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

ret =1;

vec3 ret2 = texture(sampler_main, vUv);
float noise = 1;
vec2 uv2 = 0;
vec3 uv3 = 0;
float bl = GetBlur2(vUv);
vec2 texc = bl*ret2;
vec3 foreground = 0;

uv2.x = vUv.x+abs(.05*sin(uTime*.18));
uv2.y=vUv.y+abs(.05*cos(uTime*.11));

uv3.x=.5-vUv.x/uv2.x;
uv3.y=.5-vUv.y/uv2.y;
uv3.z=vUv.x/vUv.y+uv2.x/uv2.y;

uv3.z*=.5-ret2;

noise *= lum(texture(sampler_noise_hq, uv3.xzx*uv3.xyz-foreground)*texture(sampler_main, vUv));

foreground=1*(texture(sampler_noise_hq, noise)+texture(sampler_fc_main, vUv));

ret -= ret2*noise*foreground;


  fragColor = ret;
}
